def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        base_score = 0
        for j in range(1, 20):
            if j % 5 == 0:
                factor = 1.3
            elif j % 4 == 0:
                factor = 1.15
            elif j % 3 == 0:
                factor = 1.1
            elif j % 2 == 0:
                factor = 0.9
            else:
                factor = 0.7
            base_score += factor * (1 / (j**1.5)) * (ratio ** j)
        usage_ratio = (capacity - item) / capacity
        if usage_ratio < 0.02:
            base_score *= 3
        elif usage_ratio < 0.06:
            base_score *= 2.2
        elif usage_ratio < 0.15:
            base_score *= 1.4
        elif usage_ratio < 0.3:
            base_score *= 1.0
        else:
            base_score *= 0.6
        div_counts = [2, 3, 5, 7, 11]
        divisor_score = 0
        for d in div_counts:
            if int(capacity) % d == 0:
                divisor_score += 0.07 / d * capacity
            else:
                divisor_score -= 0.04 / d * capacity
        base_score -= divisor_score / 3
        penalty = 0
        for k in range(1, 10):
            expected = item * k
            diff = abs(capacity - expected)
            threshold = 0.01 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 2 * threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.08 * k
        base_score += penalty
        if base_score < 0:
            base_score = 0
        if base_score > 2.0:
            for m in range(1, 5):
                if abs((capacity / m) - item) < 0.015 * (capacity / m):
                    base_score *= (1 + 0.06 * m)
        weighted_score = 0
        for idx, b in enumerate(bins):
            dist = abs(capacity - b)
            if dist == 0:
                weighted_score += base_score * 1.2
            elif dist < 0.05 * capacity:
                weighted_score += base_score * 0.9
            else:
                weighted_score += base_score * 0.5
        weighted_score /= max(1, len(bins))
        priorities[i] = weighted_score
    return priorities
